+  const svg = d3.select(container).append('svg');
+
+  svg.selectAll('circle')
+    .data(nodes)
+    .enter()
+    .append('circle')
+    .attr('r', d => Math.sqrt(d.cost) * 2)
+    .attr('fill', d => criticalSet.has(d.id) ? '#ff6b6b' : '#4dabf7')
+    .attr('cx', (d, i) => 100 + topo.indexOf(d.id) * 150)
+    .attr('cy', 100);
+}
