+    id: String!
+    name: String
+    nodeCount: Int!
+    edgeCount: Int!
+    criticalPath: CriticalPath!
+  }
+
+  type CriticalPath {
+    path: [Int!]!
+    cost: Float!
+  }
+
+  type Query {
+    dag(id: String!): Dag
+    dags: [Dag!]!
+  }
+`;
+
+const resolvers = {
+  Query: {
+    dag: async (_: any, { id }: { id: string }) => {
+      const dag = await manager.loadDag(id);
+      if (!dag) return null;
+
+      const result = {
+        id: dag.getId(),
+        name: dag.getName(),
+        nodeCount: dag.nodeCount,
+        edgeCount: dag.edgeCount,
+        criticalPath: dag.criticalPath(),
+      };
+
+      dag.dispose();
+      return result;
+    },
+  },
+};
