+interface WasmDagModule {
+  WasmDag: {
+    new(): WasmDagInstance;
+    from_bytes(data: Uint8Array): WasmDagInstance;
+    from_json(json: string): WasmDagInstance;
+  };
+}
+
+interface WasmDagInstance {
+  add_node(op: number, cost: number): number;
