+  PROJECT = 2,
+  /** Join operation */
+  JOIN = 3,
+  /** Aggregation (GROUP BY) */
+  AGGREGATE = 4,
+  /** Sort/ORDER BY */
+  SORT = 5,
+  /** Limit/TOP N */
+  LIMIT = 6,
+  /** Union of results */
+  UNION = 7,
+  /** Custom user-defined operator */
+  CUSTOM = 255,
+}
