+            datamap: false,
+            mmap_threshold: 0,
+        }
+    }
+}
+
+impl ReloadOptions {
+    pub fn new(datamap: bool) -> Self {
+        ReloadOptions {
+            datamap,
+            mmap_threshold: 0,
+        }
+    }
+
+    /// set mmap uasge to true
+    pub fn set_mmap(&mut self, val: bool) -> Self {
+        self.datamap = val;
+        *self
+    }
