+        let magic = u32::from_ne_bytes(it_slice);
+        assert_eq!(
+            magic, MAGICDATAP,
+            "magic not equal to MAGICDATAP in load_point"
+        );
+        //
+        let mut it_slice = [0u8; std::mem::size_of::<usize>()];
+        data_in.read_exact(&mut it_slice)?;
+        let dimension = usize::from_ne_bytes(it_slice);
+        assert_eq!(
